    if not self.component_names:
        return {}
    values = None
    for getter in (
        lambda: stream.ComponentMolarFractionValue,
        lambda: stream.ComponentMolarFraction.Values,
    ):
        try:
            values = list(getter())
            break
        except Exception:
            continue
    if values is None:
        return {}
    return {
