    for attr in (
        "StageName",
        "IFaceStageName",
        "FeedStageName",
        "DrawStageName",
        "Stage",
        "Name",
    ):
        raw = _safe_get(item, attr)
        if raw is None:
            continue
        text = str(raw).strip()
        if not text or text.lower() == str(getattr(item, "Name", "")).lower():
            if attr == "Name":
                continue
            if not text:
                continue
        # Prefer labels that look like HYSYS stage tags
