            current = _number(spec, "CurrentValue")
            if current is None or is_sentinel(current):
                raise HysysError(f"No usable CurrentValue on '{spec_name}'")
            try:
                spec.GoalValue = float(current)
                return float(current)
            except Exception as exc:
